patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..bf67e69ac1a5 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,21 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq (select (fcmp ord X, 0.0), X, 0.0), C --> fcmp oeq X, C
+      // If X is NaN: select returns 0.0, (0.0 == C) is false for non-zero C
+      // If X is ordered: select returns X, (X == C) is the same as comparing X directly
+      if (Pred == FCmpInst::FCMP_OEQ && !match(RHSC, m_AnyZeroFP())) {
+        Value *CondX, *SelectVal;
+        Constant *CondC, *FalseVal;
+        CmpPredicate CondPred;
+        if (match(LHSI, m_Select(m_FCmp(CondPred, m_Value(CondX), m_Constant(CondC)),
+                                 m_Value(SelectVal), m_Constant(FalseVal))) &&
+            CondPred == FCmpInst::FCMP_ORD &&
+            match(CondC, m_AnyZeroFP()) &&
+            match(FalseVal, m_AnyZeroFP()) &&
+            SelectVal == CondX)
+          return new FCmpInst(Pred, SelectVal, RHSC, "", &I);
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

